hero.css:
/* =====================================================
   HERO_001 — Kavya & Mihir · Royal Gujarati Palace
   All selectors scoped to .hero_001
   ===================================================== */

/* ---------- Keyframe Animations ---------- */
@keyframes hero001FadeUp {
  from { opacity: 0; transform: translateY(28px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes hero001FadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}
@keyframes hero001RotateSlow {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}
@keyframes hero001RotateSlowReverse {
  from { transform: rotate(0deg); }
  to   { transform: rotate(-360deg); }
}
@keyframes hero001FlameFlicker {
  0%,100% { transform: scaleY(1) scaleX(1) translateY(0); opacity: 1; }
  25%      { transform: scaleY(1.12) scaleX(0.88) translateY(-2px); opacity: 0.92; }
  50%      { transform: scaleY(0.94) scaleX(1.06) translateY(1px); opacity: 1; }
  75%      { transform: scaleY(1.08) scaleX(0.93) translateY(-1px); opacity: 0.95; }
}
@keyframes hero001PetalFloat {
  0%   { transform: translateY(0) rotate(0deg) scale(1); opacity: 0.55; }
  50%  { transform: translateY(-22px) rotate(18deg) scale(1.08); opacity: 0.75; }
  100% { transform: translateY(0) rotate(0deg) scale(1); opacity: 0.55; }
}
@keyframes hero001ScrollBounce {
  0%,100% { transform: translateY(0); opacity: 0.7; }
  50%      { transform: translateY(6px); opacity: 1; }
}
@keyframes hero001GlowPulse {
  0%,100% { box-shadow: 0 0 32px 6px rgba(201,168,76,0.18); }
  50%      { box-shadow: 0 0 54px 14px rgba(201,168,76,0.32); }
}
@keyframes hero001ToranSway {
  0%,100% { transform: scaleY(1); }
  50%      { transform: scaleY(1.06); }
}

/* ---------- Root Shell ---------- */
.hero_001 {
  position: relative;
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  font-family: 'Manrope', sans-serif;
  color: #f5e9cc;
  padding: 0 0 80px;
  box-sizing: border-box;
}

/* ---------- Background Layers ---------- */
.hero_001__bg-base {
  position: absolute;
  inset: 0;
  z-index: 0;
}
.hero_001__bg-gradient {
  position: absolute;
  inset: 0;
  background:
    radial-gradient(ellipse 80% 60% at 50% 30%, #3b1a08 0%, transparent 70%),
    linear-gradient(160deg, #1a0a02 0%, #2d1206 25%, #1e0d05 50%, #2a1508 75%, #120600 100%);
}
.hero_001__bg-pattern {
  position: absolute;
  inset: 0;
  opacity: 0.07;
  background-image:
    repeating-linear-gradient(
      45deg,
      transparent,
      transparent 28px,
      rgba(201,168,76,0.6) 28px,
      rgba(201,168,76,0.6) 29px
    ),
    repeating-linear-gradient(
      -45deg,
      transparent,
      transparent 28px,
      rgba(201,168,76,0.6) 28px,
      rgba(201,168,76,0.6) 29px
    );
}
.hero_001__bg-vignette {
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse 90% 90% at 50% 50%, transparent 40%, rgba(0,0,0,0.72) 100%);
}

/* ---------- Floating Petals ---------- */
.hero_001__petal {
  position: absolute;
  border-radius: 50% 10% 50% 10%;
  z-index: 1;
  pointer-events: none;
}
.hero_001__petal--1 {
  width: 14px; height: 22px;
  background: radial-gradient(ellipse, #e8843a 0%, #c9521a 100%);
  top: 12%; left: 8%;
  animation: hero001PetalFloat 5.2s ease-in-out infinite;
}
.hero_001__petal--2 {
  width: 10px; height: 18px;
  background: radial-gradient(ellipse, #f4b942 0%, #e07c1c 100%);
  top: 28%; left: 4%;
  animation: hero001PetalFloat 6.8s ease-in-out infinite 1.1s;
}
.hero_001__petal--3 {
  width: 12px; height: 20px;
  background: radial-gradient(ellipse, #e85d2a 0%, #b83a10 100%);
  top: 60%; left: 6%;
  animation: hero001PetalFloat 4.9s ease-in-out infinite 2.3s;
}
.hero_001__petal--4 {
  width: 14px; height: 22px;
  background: radial-gradient(ellipse, #e8843a 0%, #c9521a 100%);
  top: 15%; right: 8%;
  animation: hero001PetalFloat 5.6s ease-in-out infinite 0.7s;
}
.hero_001__petal--5 {
  width: 10px; height: 17px;
  background: radial-gradient(ellipse, #f4b942 0%, #e07c1c 100%);
  top: 42%; right: 5%;
  animation: hero001PetalFloat 7.1s ease-in-out infinite 1.9s;
}
.hero_001__petal--6 {
  width: 12px; height: 19px;
  background: radial-gradient(ellipse, #e85d2a 0%, #b83a10 100%);
  top: 70%; right: 7%;
  animation: hero001PetalFloat 5.3s ease-in-out infinite 3.1s;
}

/* ---------- Top Bar ---------- */
.hero_001__top-bar {
  position: relative;
  z-index: 5;
  display: flex;
  align-items: center;
  gap: 14px;
  margin-top: 44px;
  margin-bottom: 10px;
  width: 100%;
  max-width: 860px;
  padding: 0 40px;
  box-sizing: border-box;
}
.hero_001__top-bar-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(201,168,76,0.6), transparent);
}
.hero_001__top-bar-diamond {
  font-size: 13px;
  color: #c9a84c;
  opacity: 0.8;
  letter-spacing: 2px;
}

/* ---------- Main Shell (3-col layout) ---------- */
.hero_001__shell {
  position: relative;
  z-index: 5;
  display: grid;
  grid-template-columns: 160px 1fr 160px;
  align-items: center;
  width: 100%;
  max-width: 1200px;
  padding: 0 24px;
  box-sizing: border-box;
  gap: 0 20px;
  animation: hero001FadeIn 1.2s ease both;
}

/* ---------- Left / Right Decorative Columns ---------- */
.hero_001__col-left,
.hero_001__col-right {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
  padding: 20px 0;
}
.hero_001__col-right {
  transform: scaleX(-1);
}
.hero_001__col-right .hero_001__right-verse {
  transform: scaleX(-1);
}

/* Mandala */
.hero_001__mandala-wrap {
  position: relative;
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.hero_001__mandala-ring {
  position: absolute;
  border-radius: 50%;
  border: 1px solid rgba(201,168,76,0.45);
}
.hero_001__mandala-ring--outer {
  width: 120px; height: 120px;
  animation: hero001RotateSlow 28s linear infinite;
  border-style: dashed;
  border-color: rgba(201,168,76,0.3);
}
.hero_001__mandala-ring--mid {
  width: 88px; height: 88px;
  animation: hero001RotateSlowReverse 20s linear infinite;
  border-color: rgba(201,168,76,0.45);
}
.hero_001__mandala-ring--inner {
  width: 58px; height: 58px;
  animation: hero001RotateSlow 14s linear infinite;
  border-style: dotted;
  border-color: rgba(201,168,76,0.5);
}
.hero_001__mandala-center {
  position: relative;
  z-index: 2;
}
.hero_001__mandala-svg {
  width: 52px;
  height: 52px;
  animation: hero001RotateSlowReverse 35s linear infinite;
  filter: drop-shadow(0 0 6px rgba(201,168,76,0.5));
}

/* Diya */
.hero_001__diya-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
}
.hero_001__diya-flame {
  width: 14px;
  height: 22px;
  background: radial-gradient(ellipse at 50% 80%, #fff6a0 0%, #f9c840 35%, #f07010 70%, transparent 100%);
  border-radius: 50% 50% 30% 30%;
  filter: blur(1.5px);
  animation: hero001FlameFlicker 1.6s ease-in-out infinite;
  margin-bottom: -4px;
  z-index: 2;
}
.hero_001__diya-base-shell {
  width: 36px;
  height: 16px;
  background: radial-gradient(ellipse at 50% 60%, #c97a3a 0%, #7a3a10 100%);
  border-radius: 50% 50% 40% 40%;
  box-shadow: 0 4px 10px rgba(0,0,0,0.5), inset 0 -2px 4px rgba(255,200,100,0.2);
}

/* Gujarati accent text in side columns */
.hero_001__gujarati-accent {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 12px;
  color: rgba(201,168,76,0.75);
  letter-spacing: 1px;
  text-align: center;
  line-height: 1.6;
  writing-mode: vertical-rl;
  text-orientation: mixed;
}
.hero_001__left-verse,
.hero_001__right-verse {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 80px;
}

/* ---------- Centre Content ---------- */
.hero_001__center {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 40px 20px 20px;
  position: relative;
}

/* Badge */
.hero_001__badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: rgba(201,168,76,0.1);
  border: 1px solid rgba(201,168,76,0.35);
  border-radius: 100px;
  padding: 6px 20px;
  margin-bottom: 18px;
  backdrop-filter: blur(6px);
  animation: hero001FadeUp 0.8s ease both 0.2s;
}
.hero_001__badge-text {
  font-family: 'Manrope', sans-serif;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: #c9a84c;
}
.hero_001__badge-diamond {
  font-size: 8px;
  color: #c9a84c;
  opacity: 0.7;
}

/* Gujarati subtitle */
.hero_001__gujarati-sub {
  font-family: 'Noto Serif Gujarati', serif;
  font-size: 14px;
  color: rgba(245,233,204,0.6);
  letter-spacing: 1.5px;
  margin: 0 0 20px;
  animation: hero001FadeUp 0.8s ease both 0.35s;
}

/* Names */
.hero_001__names-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0;
  animation: hero001FadeUp 0.9s ease both 0.5s;
}
.hero_001__bride-name,
.hero_001__groom-name {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(62px, 9vw, 110px);
  font-weight: 600;
  line-height: 0.95;
  letter-spacing: -1px;
  margin: 0;
  background: linear-gradient(135deg, #f5e9cc 0%, #c9a84c 40%, #f5d98c 65%, #a07830 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  filter: drop-shadow(0 2px 18px rgba(201,168,76,0.3));
}
.hero_001__groom-name {
  background: linear-gradient(135deg, #a07830 0%, #f5d98c 35%, #c9a84c 60%, #f5e9cc 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero_001__ampersand-wrap {
  display: flex;
  align-items: center;
  gap: 16px;
  margin: 6px 0;
}
.hero_001__ampersand {
  font-family: 'Rozha One', serif;
  font-size: clamp(28px, 4vw, 48px);
  color: #c9a84c;
  line-height: 1;
  filter: drop-shadow(0 0 10px rgba(201,168,76,0.6));
  animation: hero001GlowPulse 3s ease-in-out infinite;
  display: inline-block;
  border-radius: 50%;
  padding: 0 6px;
}
.hero_001__ampersand-line {
  width: 60px;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(201,168,76,0.55), transparent);
}

/* Rule */
.hero_001__rule-wrap {
  display: flex;
  align-items: center;
  gap: 14px;
  margin: 22px 0 18px;
  width: 100%;
  max-width: 520px;
  animation: hero001FadeUp 0.8s ease both 0.7s;
}
.hero_001__rule-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(201,168,76,0.5), transparent);
}
.hero_001__rule-motif {
  font-size: 9px;
  color: rgba(201,168,76,0.75);
  letter-spacing: 6px;
  white-space: nowrap;
}

/* Meta (date / venue / location) */
.hero_001__meta-wrap {
  display: flex;
  align-items: flex-start;
  justify-content: center;
  gap: 20px;
  margin-bottom: 26px;
  flex-wrap: wrap;
  animation: hero001FadeUp 0.8s ease both 0.85s;
}
.hero_001__meta-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
}
.hero_001__meta-label {
  font-family: 'Manrope', sans-serif;
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: rgba(201,168,76,0.7);
}
.hero_001__meta-value {
  font-family: 'Playfair Display', serif;
  font-size: 13px;
  font-weight: 400;
  color: #f5e9cc;
  letter-spacing: 0.5px;
}
.hero_001__meta-sep {
  color: rgba(201,168,76,0.35);
  font-size: 22px;
  font-weight: 100;
  align-self: center;
  padding-top: 2px;
}

/* Hero message */
.hero_001__message {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(14px, 1.6vw, 18px);
  font-weight: 400;
  font-style: italic;
  line-height: 1.85;
  color: rgba(245,233,204,0.72);
  max-width: 600px;
  margin: 0 auto 34px;
  letter-spacing: 0.3px;
  animation: hero001FadeUp 0.8s ease both 1s;
}
.hero_001__br-hide { display: inline; }

/* CTA Button */
.hero_001__cta {
  display: inline-block;
  text-decoration: none;
  border: 1px solid rgba(201,168,76,0.6);
  border-radius: 100px;
  padding: 14px 44px;
  background: linear-gradient(135deg, rgba(201,168,76,0.15) 0%, rgba(201,168,76,0.05) 100%);
  backdrop-filter: blur(8px);
  transition: background 0.3s ease, border-color 0.3s ease, transform 0.2s ease, box-shadow 0.3s ease;
  animation: hero001FadeUp 0.8s ease both 1.15s;
  margin-bottom: 44px;
  position: relative;
  overflow: hidden;
}
.hero_001__cta::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: 100px;
  background: linear-gradient(135deg, rgba(201,168,76,0.25), transparent);
  opacity: 0;
  transition: opacity 0.3s ease;
}
.hero_001__cta:hover::before { opacity: 1; }
.hero_001__cta:hover {
  border-color: rgba(201,168,76,0.9);
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(201,168,76,0.25);
}
.hero_001__cta-inner {
  font-family: 'Manrope', sans-serif;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 3.5px;
  text-transform: uppercase;
  color: #c9a84c;
  position: relative;
  z-index: 1;
}

/* ---------- Toran (Marigold String) ---------- */
.hero_001__toran-wrap {
  position: relative;
  width: 100%;
  max-width: 560px;
  height: 44px;
  margin-top: -20px;
  animation: hero001FadeUp 0.8s ease both 1.3s;
}
.hero_001__toran-string {
  position: absolute;
  top: 10px;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, transparent, rgba(201,168,76,0.5) 10%, rgba(201,168,76,0.6) 50%, rgba(201,168,76,0.5) 90%, transparent);
  border-radius: 2px;
}
.hero_001__toran-flower {
  position: absolute;
  top: 0;
  width: 22px;
  height: 22px;
  border-radius: 50%;
  animation: hero001ToranSway 2.5s ease-in-out infinite;
}
.hero_001__toran-flower--1 { left: 0%;   background: radial-gradient(circle, #f9c840 30%, #e07c1c 100%); animation-delay: 0s; }
.hero_001__toran-flower--2 { left: 16%;  background: radial-gradient(circle, #f4843a 30%, #c93a10 100%); animation-delay: 0.3s; }
.hero_001__toran-flower--3 { left: 32%;  background: radial-gradient(circle, #f9c840 30%, #e07c1c 100%); animation-delay: 0.6s; }
.hero_001__toran-flower--4 { left: 48%;  background: radial-gradient(circle, #f4843a 30%, #c93a10 100%); animation-delay: 0.9s; transform: translateX(-50%); }
.hero_001__toran-flower--5 { right: 32%; background: radial-gradient(circle, #f9c840 30%, #e07c1c 100%); animation-delay: 0.6s; }
.hero_001__toran-flower--6 { right: 16%; background: radial-gradient(circle, #f4843a 30%, #c93a10 100%); animation-delay: 0.3s; }
.hero_001__toran-flower--7 { right: 0%;  background: radial-gradient(circle, #f9c840 30%, #e07c1c 100%); animation-delay: 0s; }

/* ---------- Bottom Bar ---------- */
.hero_001__bottom-bar {
  position: relative;
  z-index: 5;
  display: flex;
  align-items: center;
  gap: 14px;
  margin-top: 10px;
  width: 100%;
  max-width: 860px;
  padding: 0 40px;
  box-sizing: border-box;
  animation: hero001FadeIn 1s ease both 1.4s;
}
.hero_001__bottom-bar-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(201,168,76,0.4), transparent);
}
.hero_001__bottom-bar-diamond {
  font-size: 12px;
  color: rgba(201,168,76,0.6);
}

/* ---------- Scroll Hint ---------- */
.hero_001__scroll-hint {
  position: absolute;
  bottom: 24px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
  z-index: 6;
  animation: hero001FadeIn 1s ease both 1.8s;
}
.hero_001__scroll-label {
  font-family: 'Manrope', sans-serif;
  font-size: 9px;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: rgba(201,168,76,0.5);
}
.hero_001__scroll-arrow {
  font-size: 14px;
  color: rgba(201,168,76,0.6);
  animation: hero001ScrollBounce 1.8s ease-in-out infinite;
}

/* =====================================================
   RESPONSIVE — max-width: 900px
   ===================================================== */
@media (max-width: 900px) {
  .hero_001__shell {
    grid-template-columns: 90px 1fr 90px;
    gap: 0 10px;
    padding: 0 12px;
  }
  .hero_001__mandala-wrap {
    width: 80px;
    height: 80px;
  }
  .hero_001__mandala-ring--outer { width: 80px; height: 80px; }
  .hero_001__mandala-ring--mid   { width: 58px; height: 58px; }
  .hero_001__mandala-ring--inner { width: 38px; height: 38px; }
  .hero_001__mandala-svg { width: 36px; height: 36px; }
  .hero_001__gujarati-accent { font-size: 10px; }
  .hero_001__meta-wrap { gap: 12px; }
  .hero_001__meta-sep { display: none; }
  .hero_001__meta-item { flex-direction: row; align-items: center; gap: 6px; }
  .hero_001__meta-label { display: none; }
  .hero_001__message { font-size: 15px; }
  .hero_001__toran-wrap { max-width: 400px; }
}

/* =====================================================
   RESPONSIVE — max-width: 640px
   ===================================================== */
@media (max-width: 640px) {
  .hero_001 {
    padding-bottom: 70px;
  }
  .hero_001__shell {
    grid-template-columns: 1fr;
    grid-template-rows: auto auto;
    padding: 0 16px;
    gap: 0;
  }
  .hero_001__col-left,
  .hero_001__col-right {
    display: none;
  }
  .hero_001__center {
    padding: 20px 12px 16px;
  }
  .hero_001__badge {
    padding: 5px 16px;
    margin-bottom: 12px;
  }
  .hero_001__badge-text {
    font-size: 8.5px;
    letter-spacing: 2px;
  }
  .hero_001__gujarati-sub {
    font-size: 12px;
    margin-bottom: 14px;
  }
  .hero_001__bride-name,
  .hero_001__groom-name {
    font-size: clamp(52px, 16vw, 72px);
    line-height: 1;
  }
  .hero_001__ampersand {
    font-size: 30px;
  }
  .hero_001__ampersand-line {
    width: 36px;
  }
  .hero_001__rule-wrap {
    margin: 16px 0 14px;
  }
  .hero_001__meta-wrap {
    flex-direction: column;
    gap: 6px;
    margin-bottom: 18px;
  }
  .hero_001__meta-item {
    flex-direction: column;
    gap: 2px;
  }
  .hero_001__meta-label {
    display: block;
  }
  .hero_001__meta-value {
    font-size: 12px;
  }
  .hero_001__message {
    font-size: 13.5px;
    line-height: 1.75;
    margin-bottom: 24px;
  }
  .hero_001__br-hide {
    display: none;
  }
  .hero_001__cta {
    padding: 12px 32px;
    margin-bottom: 32px;
  }
  .hero_001__cta-inner {
    font-size: 10px;
    letter-spacing: 2.5px;
  }
  .hero_001__toran-wrap {
    max-width: 300px;
  }
  .hero_001__toran-flower {
    width: 18px;
    height: 18px;
  }
  .hero_001__top-bar,
  .hero_001__bottom-bar {
    padding: 0 20px;
  }
  .hero_001__petal--1,
  .hero_001__petal--2,
  .hero_001__petal--3,
  .hero_001__petal--4,
  .hero_001__petal--5,
  .hero_001__petal--6 {
    opacity: 0.35;
  }
}
